                  </p>
                  <p className="text-sm text-muted-foreground">
                    {names.suppliers.get(receipt.supplierId) ??
                      receipt.supplierId}{" "}
                    →{" "}
                    {names.warehouses.get(receipt.warehouseId) ??
                      receipt.warehouseId}
                  </p>
                </li>
              ))}
            </ul>
          </CardContent>
        </Card>
      </div>
    </div>
