  7	namespace InventoryFlow.Infrastructure.Inventory;
  8	
  9	/// <summary>Persists inventory movements and materialized balances atomically.</summary>
 10	public sealed class EfInventoryLedger(ApplicationDbContext dbContext) : IInventoryLedger
 11	{
 12	    public async Task<InventoryMovement?> RecordAsync(Guid workspaceId, Guid warehouseId, Guid productId, InventoryMovementType type,
 13	        decimal quantity, string idempotencyKey, DateTimeOffset occurredAtUtc, CancellationToken cancellationToken)
 14	    {
 15	        quantity = InventoryMovement.ValidateQuantity(quantity);
 16	        idempotencyKey = InventoryMovement.NormalizeIdempotencyKey(idempotencyKey);
 17	        var strategy = dbContext.Database.CreateExecutionStrategy();
 18	        return await strategy.ExecuteAsync(async () =>
 19	        {
 20	            await using var transaction = await dbContext.Database.BeginTransactionAsync(IsolationLevel.Serializable, cancellationToken);
 21	            var movement = await new InventoryLedgerWriter(dbContext).RecordAsync(workspaceId, warehouseId, productId, type, quantity,
 22	                idempotencyKey, occurredAtUtc, Guid.NewGuid(), cancellationToken);
 23	            if (movement is not null && dbContext.Entry(movement).State == EntityState.Added)
 24	                await dbContext.SaveChangesAsync(cancellationToken);
 25	            await transaction.CommitAsync(cancellationToken);
 26	            return movement;
 27	        });
 28	    }
 29	
 30	    public async Task<IReadOnlyList<InventoryBalance>> ListBalancesAsync(Guid workspaceId, Guid? warehouseId, Guid? productId,
 31	        CancellationToken cancellationToken)
 32	    {
 33	        var query = dbContext.InventoryBalances.AsNoTracking().Where(balance => balance.WorkspaceId == workspaceId);
 34	        if (warehouseId.HasValue) query = query.Where(balance => balance.WarehouseId == warehouseId.Value);
 35	        if (productId.HasValue) query = query.Where(balance => balance.ProductId == productId.Value);
 36	        return await query.OrderBy(balance => balance.WarehouseId).ThenBy(balance => balance.ProductId).ToListAsync(cancellationToken);
 37	    }
 38	}
 39	using InventoryFlow.Domain.Entities;
 40	using InventoryFlow.Infrastructure.Persistence;
 41	using Microsoft.EntityFrameworkCore;
 42	
 43	namespace InventoryFlow.Infrastructure.Inventory;
 44	
 45	/// <summary>Shared transaction-aware inventory balance and movement writer.</summary>
 46	internal sealed class InventoryLedgerWriter(ApplicationDbContext dbContext)
 47	{
 48	    internal async Task<InventoryMovement?> RecordAsync(Guid workspaceId, Guid warehouseId, Guid productId, InventoryMovementType type,
 49	        decimal quantity, string idempotencyKey, DateTimeOffset occurredAtUtc, Guid movementId, CancellationToken cancellationToken)
 50	    {
 51	        quantity = InventoryMovement.ValidateQuantity(quantity);
 52	        idempotencyKey = InventoryMovement.NormalizeIdempotencyKey(idempotencyKey);
 53	        if (!Enum.IsDefined(type)) throw new ArgumentOutOfRangeException(nameof(type));
 54	
 55	        var existing = await dbContext.InventoryMovements.SingleOrDefaultAsync(movement => movement.WorkspaceId == workspaceId &&
 56	            movement.IdempotencyKey == idempotencyKey, cancellationToken);
 57	        if (existing is not null) return existing;
 58	
 59	        var warehouseExists = await dbContext.Warehouses.AnyAsync(warehouse => warehouse.Id == warehouseId &&
 60	            warehouse.WorkspaceId == workspaceId && warehouse.ArchivedAtUtc == null, cancellationToken);
 61	        var productExists = await dbContext.Products.AnyAsync(product => product.Id == productId &&
 62	            product.WorkspaceId == workspaceId && product.ArchivedAtUtc == null, cancellationToken);
 63	        if (!warehouseExists || !productExists) return null;
 64	
 65	        var balance = await dbContext.InventoryBalances.SingleOrDefaultAsync(item => item.WorkspaceId == workspaceId &&
 66	            item.WarehouseId == warehouseId && item.ProductId == productId, cancellationToken);
 67	        if (balance is null)
 68	        {
 69	            balance = new InventoryBalance(workspaceId, warehouseId, productId, 0m);
 70	            dbContext.InventoryBalances.Add(balance);
 71	        }
 72	
 73	        balance.Apply(type == InventoryMovementType.Receipt ? quantity : -quantity);
 74	        var movement = new InventoryMovement(movementId, workspaceId, warehouseId, productId, type, quantity, idempotencyKey,
 75	            balance.Quantity, occurredAtUtc);
 76	        dbContext.InventoryMovements.Add(movement);
 77	        return movement;
 78	    }
 79	}
