  1	import { useState } from "react"
  2	import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query"
  3	
  4	import { PageHeader } from "@/components/shared/PageHeader"
  5	import { Button } from "@/components/ui/button"
  6	import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
  7	import { useAuthStore } from "@/features/auth/auth-store"
  8	import { listProducts } from "@/features/products/products-api"
  9	import {
 10	  listSalesFulfillments,
 11	  recordSalesFulfillment,
 12	} from "@/features/sales/sales-api"
 13	import { salesFulfillmentSchema } from "@/features/sales/sales-schema"
 14	import type { RecordSalesFulfillmentPayload } from "@/features/sales/types"
 15	import { listWarehouses } from "@/features/warehouses/warehouses-api"
 16	
 17	const key = (name: string, userId: string, workspaceId: string) =>
 18	  [name, userId, workspaceId] as const
 19	const readError = (error: unknown) => {
 20	  if (typeof error === "object" && error && "response" in error) {
 21	    const data = (
 22	      error as { response?: { data?: { detail?: string; title?: string } } }
 23	    ).response?.data
 24	    return data?.detail ?? data?.title ?? "Unable to fulfill the sale."
 25	  }
 26	  return "Unable to fulfill the sale."
 27	}
