 12	} from "@/features/sales/sales-api"
 13	import { salesFulfillmentSchema } from "@/features/sales/sales-schema"
 14	import type { RecordSalesFulfillmentPayload } from "@/features/sales/types"
 15	import { listWarehouses } from "@/features/warehouses/warehouses-api"
 16	
 17	const key = (name: string, userId: string, workspaceId: string) =>
 18	  [name, userId, workspaceId] as const
 19	const readError = (error: unknown) => {
 20	  if (typeof error === "object" && error && "response" in error) {
 21	    const data = (
 22	      error as { response?: { data?: { detail?: string; title?: string } } }
 23	    ).response?.data
 24	    return data?.detail ?? data?.title ?? "Unable to fulfill the sale."
 25	  }
 26	  return "Unable to fulfill the sale."
 27	}
 28	
 29	export function Component() {
 30	  const queryClient = useQueryClient()
 31	  const user = useAuthStore((state) => state.user)
 32	  const userId = user?.id ?? "anonymous"
 33	  const workspaceId = user?.workspace.id ?? "none"
 34	  const [warehouseId, setWarehouseId] = useState("")
 35	  const [productId, setProductId] = useState("")
 36	  const [quantity, setQuantity] = useState("")
 37	  const [formError, setFormError] = useState("")
 38	  const [retryFulfillment, setRetryFulfillment] =
 39	    useState<RecordSalesFulfillmentPayload | null>(null)
 40	  const warehouses = useQuery({
 41	    queryKey: key("warehouses", userId, workspaceId),
 42	    queryFn: listWarehouses,
 43	    enabled: user !== null,
 44	  })
 45	  const products = useQuery({
 46	    queryKey: key("products", userId, workspaceId),
 47	    queryFn: listProducts,
 48	    enabled: user !== null,
 49	  })
 50	  const fulfillments = useQuery({
 51	    queryKey: key("sales-fulfillments", userId, workspaceId),
 52	    queryFn: listSalesFulfillments,
 53	    enabled: user !== null,
 54	  })
 55	  const mutation = useMutation({
 56	    mutationKey: key("sales-fulfillments", userId, workspaceId),
 57	    mutationFn: recordSalesFulfillment,
 58	    onSuccess: () => {
 59	      setFormError("")
 60	      setRetryFulfillment(null)
 61	      setQuantity("")
 62	      queryClient.invalidateQueries({
 63	        queryKey: key("sales-fulfillments", userId, workspaceId),
 64	      })
 65	      queryClient.invalidateQueries({
 66	        queryKey: ["inventory", "balances", userId, workspaceId],
 67	      })
 68	    },
 69	    onError: (error, variables) => {
 70	      setRetryFulfillment(variables)
 71	      setFormError(readError(error))
 72	    },
 73	  })
 74	  const submit = () => {
 75	    const parsed = salesFulfillmentSchema.safeParse({
 76	      warehouseId,
 77	      productId,
 78	      quantity,
 79	    })
 80	    if (!parsed.success) {
 81	      setFormError(
 82	        parsed.error.issues[0]?.message ?? "Check the fulfillment details."
 83	      )
 84	      return
 85	    }
 86	    setFormError("")
 87	    mutation.mutate({ ...parsed.data, idempotencyKey: crypto.randomUUID() })
 88	  }
 89	  const loading = warehouses.isLoading || products.isLoading
 90	  const names = {
 91	    warehouses: new Map(warehouses.data?.map((x) => [x.id, x.name])),
 92	    products: new Map(products.data?.map((x) => [x.id, x.name])),
 93	  }
 94	  const disabled = loading || mutation.isPending
 95	  return (
 96	    <div className="space-y-6">
 97	      <PageHeader
 98	        title="Sales"
 99	        description="Fulfill single-line sales directly from inventory."
100	      />
101	      <div className="grid gap-6 xl:grid-cols-[22rem_minmax(0,1fr)]">
102	        <Card>
103	          <CardHeader>
104	            <CardTitle>Fulfill sale</CardTitle>
105	          </CardHeader>
106	          <CardContent>
107	            <div className="space-y-4">
108	              {loading ? (
109	                <p className="text-muted-foreground">Loading catalog…</p>
110	              ) : null}
111	              {warehouses.isError || products.isError ? (
112	                <p className="text-destructive" role="alert">
113	                  {readError(warehouses.error ?? products.error)}
114	                </p>
115	              ) : null}
116	              <label className="block text-sm">
117	                Warehouse
118	                <select
119	                  className="mt-1 w-full rounded-md border bg-background p-2"
120	                  disabled={disabled}
121	                  onChange={(e) => setWarehouseId(e.target.value)}
122	                  value={warehouseId}
123	                >
124	                  <option value="">Choose a warehouse</option>
125	                  {warehouses.data?.map((x) => (
126	                    <option key={x.id} value={x.id}>
127	                      {x.name}
128	                    </option>
129	                  ))}
130	                </select>
131	              </label>
132	              <label className="block text-sm">
133	                Product
134	                <select
135	                  className="mt-1 w-full rounded-md border bg-background p-2"
136	                  disabled={disabled}
137	                  onChange={(e) => setProductId(e.target.value)}
138	                  value={productId}
139	                >
140	                  <option value="">Choose a product</option>
141	                  {products.data?.map((x) => (
142	                    <option key={x.id} value={x.id}>
143	                      {x.name} ({x.sku})
144	                    </option>
145	                  ))}
146	                </select>
147	              </label>
148	              <label className="block text-sm">
149	                Quantity
150	                <input
151	                  className="mt-1 w-full rounded-md border bg-background p-2"
152	                  disabled={disabled}
153	                  inputMode="decimal"
154	                  onChange={(e) => setQuantity(e.target.value)}
155	                  placeholder="0.0000"
156	                  value={quantity}
157	                />
158	              </label>
159	              {formError ? (
160	                <p className="text-sm text-destructive" role="alert">
161	                  {formError}
162	                </p>
163	              ) : null}
164	              {retryFulfillment ? (
165	                <Button
166	                  disabled={mutation.isPending}
167	                  onClick={() => mutation.mutate(retryFulfillment)}
168	                  type="button"
169	                  variant="outline"
170	                >
171	                  Retry fulfillment
172	                </Button>
173	              ) : null}
174	              <Button disabled={disabled} onClick={submit} type="button">
175	                {mutation.isPending ? "Fulfilling…" : "Fulfill sale"}
176	              </Button>
177	            </div>
178	          </CardContent>
179	        </Card>
180	        <Card>
181	          <CardHeader>
182	            <CardTitle>Fulfillment history</CardTitle>
183	          </CardHeader>
184	          <CardContent>
185	            {fulfillments.isLoading ? (
186	              <p className="text-muted-foreground">Loading fulfillments…</p>
187	            ) : null}
188	            {fulfillments.isError ? (
189	              <p className="text-destructive" role="alert">
190	                {readError(fulfillments.error)}
191	              </p>
192	            ) : null}
193	            {fulfillments.data?.length === 0 ? (
194	              <p className="text-muted-foreground">
195	                No sales fulfillments yet.
196	              </p>
197	            ) : null}
198	            <ul className="divide-y">
199	              {fulfillments.data?.map((fulfillment) => (
200	                <li className="py-3" key={fulfillment.id}>
201	                  <p className="font-medium">
202	                    {names.products.get(fulfillment.productId) ??
203	                      fulfillment.productId}{" "}
204	                    · {fulfillment.quantity}
205	                  </p>
206	                  <p className="text-sm text-muted-foreground">
207	                    {names.warehouses.get(fulfillment.warehouseId) ??
208	                      fulfillment.warehouseId}
209	                  </p>
210	                </li>
211	              ))}
212	            </ul>
213	          </CardContent>
214	        </Card>
215	      </div>
216	    </div>
217	  )
218	}
